```php
function total($arr) {
  $s = 0;
  foreach ($arr as $n) { $s += $n; }
  return $s;
}
echo total([1, 2, 3]);
```

```php
function classer($notes) {
  foreach ($notes as $n) {
    echo $n >= 10 ? "admis " : "recale ";
  }
}
classer([15, 8]);
```

